sql:
SELECT prerequisites
FROM quests
WHERE name = 'Out of Time';

SELECT name, difficulty_level 
FROM quests 
WHERE quest_type = 'main' AND difficulty_level = 'medium';

external_knowledge:
- "where they are set" refers to the location of the quest;
- "reward specifics" includes the type, quantity, and value of the reward;
- "preceding quests" refers to the prerequisite quests;
- Quests without prerequisites will list the "preceding quests" as null or not present.

sql:
SELECT name, description
FROM quests
WHERE difficulty_level > (
    SELECT AVG(difficulty_level)
    FROM quests
);

external_knowledge:
- 'main character' refers to the character with a character_id of 10;
- 'bestowed by' indicates the quest's given_by_id matches the main character's ID;
- 'places where the main character can be found' refers to locations where the character with the ID of 10 is present, represented by the location_id in the characters table.

sql:
SELECT quests.name AS "Quest Name", rewards.name AS "Reward Name"
FROM quests
JOIN rewards ON quests.reward_id = rewards.reward_id;

SELECT characters.name AS character_name, character_progress.progress AS quest_progress
FROM characters
INNER JOIN character_progress ON characters.character_id = character_progress.character_id;

SELECT name
FROM quests
WHERE quest_id NOT IN (
  SELECT quest_id
  FROM quest_prerequisites
);

SELECT quests.name AS Quest_Name, locations.name AS Location_Name
FROM quests
INNER JOIN locations ON quests.location_id = locations.location_id;

external_knowledge:
- "heroes" refers to characters in the database;
- "challenges" refer to quests, filtered to those with a status of 'completed';
- "treasure threshold" metaphorically represents the reward value greater than 200;
- "stories behind the lands" represents the locations where the quests took place;
- "treasures they've won" refers to the descriptions of the rewards;
- "dates they claimed victory" refers to the dates on which the quests were completed.

sql:
SELECT form_id
FROM quests
WHERE quest_id = 0;

SELECT c.character_id, c.name
FROM characters c
LEFT JOIN character_progress cp ON c.character_id = cp.character_id AND cp.completion_date = '2023-01-01';
